  function persist(){try{localStorage.setItem(SAVE_KEY,JSON.stringify(save))}catch(e){}}

  function upgradePrice(type){let base=type==='chassis'?70:type==='weapon'?80:65;return Math.floor(base*Math.pow(1.6,save[type]||0))}
  function maxHp(){return 100+save.chassis*14}
