  function lootMultiplier(nextTier){let singularity=hasSynergy('singularity')?1.18:1,salvage=1+Math.min(.6,save.salvage*.035),recycler=1+schematicLevel('recycler')*.05,routeBonus=routeConfig()?routeConfig().scrap:1;return (1+(depth-1)*.11)*(1+(nextTier==null?riskTier:nextTier)*.32)*salvage*singularity*recycler*routeBonus}
  function lootGlyph(item){return item.form==='gear'?'\u2699':item.form==='coil'?'\u223F':item.form==='bolt'?'\u2020':item.form==='ring'?'\u25CE':item.form==='gauge'?'\u25D4':item.form==='lens'?'\u25C9':item.form==='core'?'\u2726':item.form==='canister'?'\u25A3':'\u25C6'}
  function lootRarityRoll(elite,minimum){
    let routeBonus=routeConfig()?routeConfig().lootRare:0,r=Math.random(),legendary=.0008+(depth-1)*.00008+riskTier*.00018+(elite?.0012:0)+routeBonus*.004,mythic=.008+(depth-1)*.0015+riskTier*.002+(elite?.02:0)+routeBonus*.04,epic=.045+(depth-1)*.008+riskTier*.012+(elite?.05:0)+routeBonus*.15,rare=.19+(depth-1)*.018+riskTier*.03+(elite?.1:0)+routeBonus,rarity=r<legendary?'legendary':r<legendary+mythic?'mythic':r<legendary+mythic+epic?'epic':r<legendary+mythic+epic+rare?'rare':'common';
    if(minimum&&LOOT_RARITIES[rarity].rank<LOOT_RARITIES[minimum].rank)rarity=minimum;return rarity
  }
