  function lootManifest(){return Object.values(lootBag).sort((a,b)=>LOOT_RARITIES[LOOT_BY_ID[b.id].rarity].rank-LOOT_RARITIES[LOOT_BY_ID[a.id].rarity].rank||b.value-a.value)}
  function bestLootEntry(){return lootManifest()[0]||null}
  function formatTime(seconds){seconds=Math.max(0,Math.floor(seconds||0));return Math.floor(seconds/60)+':'+String(seconds%60).padStart(2,'0')}
  function depthForElapsed(time){let value=1;for(let i=1;i<DEPTH_THRESHOLDS.length;i++)if(time>=DEPTH_THRESHOLDS[i])value=i+1;return Math.min(5,value)}
  function zoneProgress(){if(depth>=5)return 1;let start=DEPTH_THRESHOLDS[depth-1],end=DEPTH_THRESHOLDS[depth];return Math.max(0,Math.min(1,(elapsed-start)/(end-start)))}
  function blueprintTier(id){let copies=save.blueprints[id].copies;return copies>=BLUEPRINT_THRESHOLDS[3]?3:copies>=BLUEPRINT_THRESHOLDS[2]?2:copies>=BLUEPRINT_THRESHOLDS[1]?1:0}
