  function blueprintProgress(record,tier){let goal=blueprintGoal(tier);return tier===3?100:Math.min(100,record.copies/goal*100)}
  function tuneCost(id){let record=save.blueprints[id],tier=blueprintTier(id);return Math.floor(80*(record.tune+1)*(1+tier*.45))}
  function modulePower(id){return cargo.reduce((sum,m)=>sum+(m.id===id?(m.power||(m.rare?2:1)):0),0)}
  function activeSynergies(){return SYNERGIES.filter(s=>s.needs.every(id=>modulePower(id)>0))}
  function hasSynergy(id){return activeSynergies().some(s=>s.id===id)}
  function cargoStats(){let over=modulePower('overdrive'),volatile=modulePower('volatile'),plating=platingProtection(modulePower('plating')),flux=hasSynergy('flux'),kinetic=hasSynergy('kinetic'),dashBase=flux?1.55:2.2,dashTech=1-schematicLevel('thrusters')*.06;return {burst:Math.min(3,modulePower('burst')),magnet:modulePower('magnet')*48,shields:baseShields()+plating.shields,armor:plating.armor,speed:1+over*.12+(flux ? .07 : 0),fire:Math.max(.55,1-over*.11),damage:1+volatile*.34,hp:Math.max(.58,1-volatile*.11),dashCd:dashBase*dashTech,ram:kinetic?34+shotDamage()*1.2:0,shrapnel:hasSynergy('shrapnel'),counter:hasSynergy('counter'),flux}}
  function blueprintCount(){return MODULE_IDS.reduce((sum,id)=>sum+save.blueprints[id].copies,0)}
  function contractReady(){return save.cores>=3&&blueprintCount()>=12}
  function synergyForPickup(id){return SYNERGIES.find(s=>s.needs.includes(id)&&s.needs.some(other=>other!==id&&modulePower(other)>0))}

  function resize(){const r=canvas.getBoundingClientRect();dpr=Math.min(2,window.devicePixelRatio||1);W=Math.max(1,r.width);H=Math.max(1,r.height);canvas.width=Math.floor(W*dpr);canvas.height=Math.floor(H*dpr);ctx.setTransform(dpr,0,0,dpr,0,0)}
  function setView(next){mode=next;ui.base.classList.toggle('active',next==='base');ui.expedition.classList.toggle('active',next==='run');setMusicMode(next);if(next==='run')requestAnimationFrame(()=>{resize();last=performance.now()})}
  function notice(text,tone){ui.notice.textContent=text;ui.notice.style.borderColor=tone||'';ui.notice.classList.add('show');clearTimeout(notice.t);notice.t=setTimeout(()=>ui.notice.classList.remove('show'),1700)}
