  function ensureAudio(){if(!save.settings.sound)return null;try{audio.ctx=audio.ctx||new (window.AudioContext||window.webkitAudioContext)();if(audio.ctx.state==='suspended')audio.ctx.resume();if(!audio.timer&&typeof window.setInterval==='function')audio.timer=window.setInterval(musicStep,420);return audio.ctx}catch(e){return null}}
  function tone(freq,duration,volume,type,slide,delay){let a=ensureAudio();if(!a)return;let o=a.createOscillator(),g=a.createGain(),t=a.currentTime+(delay||0);o.type=type||'triangle';o.frequency.setValueAtTime(Math.max(25,freq),t);if(slide)o.frequency.exponentialRampToValueAtTime(Math.max(25,slide),t+duration*.85);g.gain.setValueAtTime(.0001,t);g.gain.exponentialRampToValueAtTime(volume||.02,t+.008);g.gain.exponentialRampToValueAtTime(.0001,t+duration);o.connect(g);g.connect(a.destination);o.start(t);o.stop(t+duration+.02)}
  function musicStep(){if(!save.settings.sound||!audio.ctx)return;let sets=audio.mode==='boss'?[55,55,65,49,73,65,55,49]:audio.mode==='run'?[110,131,147,98,110,165,147,131]:[82,98,110,73,82,123,110,98],notes=sets[audio.step++%sets.length];tone(notes,audio.mode==='boss' ? .32 : .24,audio.mode==='boss' ? .012 : .008,'sine',notes*.998);if(audio.step%4===0)tone(notes*2,.12,.006,'triangle',notes*1.5,.06)}
  function setMusicMode(next){audio.mode=next==='run'?(bossActive?'boss':'run'):'base';if(audio.ctx)ensureAudio()}
  function sound(name){
    if(!save.settings.sound)return;ensureAudio();if(name==='shoot'){tone(250,.055,.018,'square',155);tone(620,.035,.009,'triangle',310)}else if(name==='hit'){tone(105,.06,.024,'square',65);tone(900,.035,.008,'sawtooth',320)}else if(name==='kill'){tone(145,.11,.025,'square',48);tone(520,.08,.012,'triangle',760,.025)}else if(name==='pickup'){tone(540,.08,.018,'triangle',790)}else if(name==='hurt'){tone(92,.2,.042,'sawtooth',38);tone(46,.24,.02,'square',35)}else if(name==='upgrade'){tone(330,.13,.02,'triangle',660);tone(495,.14,.015,'triangle',990,.08)}else if(name==='rare'){tone(660,.2,.025,'triangle',1320);tone(990,.24,.018,'sine',1480,.08)}else if(name==='legendary'){tone(330,.42,.035,'triangle',1320);tone(495,.38,.028,'sine',1480,.08);tone(660,.34,.022,'triangle',1760,.16)}else if(name==='boss'){tone(58,.34,.045,'sawtooth',31);tone(116,.28,.018,'square',55,.04)}else if(name==='shield'){tone(780,.12,.025,'sine',1280);tone(390,.15,.012,'triangle',910)}else if(name==='dash'){tone(180,.1,.018,'sawtooth',520)}else tone(150,.1,.018,'triangle',260)
  }

  function refreshBase(){
    ui.bank.textContent=Math.floor(save.scrap);ui.cores.textContent=save.cores;ui.best.textContent=save.best;ui.chassisLevel.textContent=save.chassis;ui.weaponLevel.textContent=save.weapon;ui.salvageLevel.textContent=save.salvage;ui.maxHp.textContent=maxHp();ui.damage.textContent=shotDamage();ui.magnet.textContent=magnetRange();
    for(const type of ['chassis','weapon','salvage']){let button=ui['upgrade'+type[0].toUpperCase()+type.slice(1)],cost=upgradePrice(type);ui[type+'Cost'].textContent=cost;button.disabled=save.scrap<cost}
    let secured=MODULE_IDS.reduce((sum,id)=>sum+save.blueprints[id].copies,0),upgrades=save.chassis+save.weapon+save.salvage;ui.scene.classList.toggle('evolved1',upgrades>=2||secured>=1);ui.scene.classList.toggle('evolved2',upgrades>=5||secured>=4);ui.scene.classList.toggle('evolved3',upgrades>=9||secured>=9);
    if(save.starter){ui.starterIcon.textContent=MODULES[save.starter].icon;ui.starterName.textContent=MODULES[save.starter].name.toUpperCase()+' '+blueprintMark(blueprintTier(save.starter))}else{ui.starterIcon.textContent='+';ui.starterName.textContent='NONE EQUIPPED'}
    let copies=blueprintCount(),corePart=Math.min(1,save.cores/3),copyPart=Math.min(1,copies/12),progress=(corePart+copyPart)*50;ui.contractReadout.textContent=Math.min(3,save.cores)+'/3 CORES · '+Math.min(12,copies)+'/12 BLUEPRINTS';ui.contractFill.style.width=progress+'%';ui.contractTracker.classList.toggle('complete',contractReady());ui.contractTitle.textContent=contractReady()?'LOWER VAULT ACCESS GRANTED':'BREACH THE LOWER VAULT';
  }
